def solve(nums: list[int]) -> int:
    def is_prime(n: int) -> bool:
        if n <= 1:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n ** 0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    sum_a = 0
    sum_b = 0

    for index, num in enumerate(nums):
        if is_prime(index):
            sum_a += num
        else:
            sum_b += num

    return abs(sum_a - sum_b)
